import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is slope?", a: "Slope measures how steep a line is. It is the change in y divided by the change in x, often called rise over run." },
  { q: "How do you calculate slope from two points?", a: "Use m = (y2 - y1) / (x2 - x1). Subtract the y-values, subtract the x-values, then divide rise by run." },
  { q: "What is slope-intercept form?", a: "Slope-intercept form is y = mx + b, where m is the slope and b is the y-intercept. It shows both steepness and where the line crosses the y-axis." },
  { q: "What does a negative slope mean?", a: "A negative slope means the line moves downward as x increases. In other words, y decreases from left to right." },
  { q: "How do you know if two lines are parallel or perpendicular?", a: "Parallel lines have the same slope. Perpendicular lines have slopes that multiply to -1, meaning one slope is the negative reciprocal of the other." },
];

const fmt = (value: number) => Number(value.toFixed(6)).toLocaleString();

export default function SlopeCalculator() {
  const [x1, setX1] = useState(1);
  const [y1, setY1] = useState(2);
  const [x2, setX2] = useState(5);
  const [y2, setY2] = useState(10);
  const [compareSlope, setCompareSlope] = useState(-0.5);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    const run = x2 - x1;
    const rise = y2 - y1;
    if (run === 0) return { slope: "Undefined", equation: `x = ${fmt(x1)}`, angle: "90 deg", relation: "A vertical line is parallel to another vertical line and perpendicular to a horizontal line.", step: `Run = ${x2} - ${x1} = 0, so the slope is undefined.` };
    const m = rise / run;
    const b = y1 - m * x1;
    const angle = Math.atan(m) * 180 / Math.PI;
    const relation = Math.abs(m - compareSlope) < 0.000001 ? "Parallel to the comparison slope." : Math.abs(m * compareSlope + 1) < 0.000001 ? "Perpendicular to the comparison slope." : "Neither parallel nor perpendicular to the comparison slope.";
    const sign = b >= 0 ? "+" : "-";
    return { slope: fmt(m), equation: `y = ${fmt(m)}x ${sign} ${fmt(Math.abs(b))}`, angle: `${fmt(angle)} deg`, relation, step: `m = (${y2} - ${y1}) / (${x2} - ${x1}) = ${rise} / ${run} = ${fmt(m)}. b = ${y1} - (${fmt(m)} x ${x1}) = ${fmt(b)}.` };
  }, [x1, y1, x2, y2, compareSlope]);

  return (
    <>
      <SEOHead title="Free Slope Calculator Online - Calculate Line Slope and Equation Instantly | CalcHive" description="Free online slope calculator. Calculate the slope of any line from two points, find the line equation in slope-intercept form and angle of inclination instantly. 100% free, no signup required." canonical="/slope-calculator" keywords="free slope calculator, slope of a line calculator free online, slope intercept form calculator free, rise over run calculator free, line equation calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Slope Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this slope of a line calculator free online to find slope, line equation, angle, and line relationships from two points.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-6">
            <div><label htmlFor="x1" className="text-sm font-semibold text-foreground block mb-2">x1</label><input id="x1" type="number" inputMode="decimal" value={x1} onChange={(event) => setX1(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="y1" className="text-sm font-semibold text-foreground block mb-2">y1</label><input id="y1" type="number" inputMode="decimal" value={y1} onChange={(event) => setY1(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="x2" className="text-sm font-semibold text-foreground block mb-2">x2</label><input id="x2" type="number" inputMode="decimal" value={x2} onChange={(event) => setX2(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="y2" className="text-sm font-semibold text-foreground block mb-2">y2</label><input id="y2" type="number" inputMode="decimal" value={y2} onChange={(event) => setY2(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <div className="mb-8"><label htmlFor="compare-slope" className="text-sm font-semibold text-foreground block mb-2">Compare with slope</label><input id="compare-slope" type="number" inputMode="decimal" step="0.01" value={compareSlope} onChange={(event) => setCompareSlope(Number(event.target.value))} className={inputClass} /></div>
          <motion.div key={`${x1}-${y1}-${x2}-${y2}-${compareSlope}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Slope</p><p className="text-5xl font-black text-white tracking-tight" data-testid="result-slope">{result.slope}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Equation</p><p className="text-xl font-extrabold text-foreground">{result.equation}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Angle</p><p className="text-xl font-extrabold text-foreground">{result.angle}</p></div></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-sm text-foreground mb-2">{result.relation}</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate the Slope of a Line for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two points and this rise over run calculator free tool computes the slope with a clear step-by-step solution.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Find the Equation of a Line from Two Points</h2><p className="text-muted-foreground leading-relaxed">After finding slope, the calculator solves for b so the line equation calculator free result appears in slope-intercept form.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Algebra Slope Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this free slope calculator to check homework, graph lines, and test whether two slopes are parallel or perpendicular.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/slope-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


